"""
Figure 10.38 – τ₂ for closed elliptic jets
Analytical curve fit to digitized data (no interpolation noise).

Formula:  τ₂ = a · (lt/B)^b  /  (1 + c · (lt/B)^d)
Fitted parameters: a=5.026874, b=1.157340, c=3.676760, d=1.434704
R² = 0.99968,  RMSE = 0.00597,  max error = 0.020  (vs raw digitized points)

Usage
-----
Run interactively:   python tau2_lookup.py
Import:              from tau2_lookup import get_tau2
                     tau2 = get_tau2(1.2)
"""

import numpy as np
import matplotlib.pyplot as plt

# ── Fitted parameters (rational power law) ───────────────────────────────
_A = 5.026874
_B = 1.157340
_C = 3.676760
_D = 1.434704

_X_MIN = 0.0
_X_MAX = 2.0   # reliable range from digitized figure


def get_tau2(lt_over_B: float) -> float:
    """
    Return τ₂ (closed jet) for a given lt/B ratio.

    Uses the analytical fit:  τ₂ = a · x^b / (1 + c · x^d)
    with a=5.0269, b=1.1573, c=3.6768, d=1.4347  (R²=0.9997)

    Parameters
    ----------
    lt_over_B : float
        Tail length / tunnel width  (reliable range: 0 – 2)

    Returns
    -------
    float
        τ₂  (returns NaN with a warning if outside valid range)
    """
    x = float(lt_over_B)
    if not (_X_MIN <= x <= _X_MAX):
        print(f"  ⚠  lt/B = {x} is outside the fitted range [{_X_MIN}, {_X_MAX}].")
        return float("nan")
    if x == 0.0:
        return 0.0
    return _A * x**_B / (1.0 + _C * x**_D)


