def plot_figure(query_x: float | None = None, show_raw: bool = True):
    x_raw = np.array([p[0] for p in _DATA])
    y_raw = np.array([p[1] for p in _DATA])

    x_fine = np.linspace(0.001, 2.0, 600)
    y_fit  = np.array([get_tau2(xi) for xi in x_fine])

    fig, axes = plt.subplots(1, 2, figsize=(13, 5))

    for ax, show_pts in zip(axes, [False, True]):
        ax.plot(x_fine, y_fit, "k-", linewidth=1.8,
                label=r"Analytical fit:  $\tau_2 = \frac{a\,x^b}{1+c\,x^d}$")
        if show_pts:
            ax.scatter(x_raw, y_raw, s=8, color="steelblue", zorder=3,
                       alpha=0.6, label="Digitized points")

        if query_x is not None:
            query_y = get_tau2(query_x)
            if not np.isnan(query_y):
                ax.axvline(query_x, color="tab:red", linestyle="--",
                           linewidth=0.9, alpha=0.8)
                ax.axhline(query_y, color="tab:red", linestyle="--",
                           linewidth=0.9, alpha=0.8)
                ax.scatter([query_x], [query_y], color="tab:red", zorder=5, s=60,
                           label=f"$l_t/B={query_x:.3f}$  →  $\\tau_2={query_y:.4f}$")

        ax.set_xlim(0, 2.0)
        ax.set_ylim(0, 1.2)
        ax.set_xlabel(r"Tail length / Tunnel width,  $l_t\,/\,B$", fontsize=11)
        ax.set_ylabel(r"$\tau_2$", fontsize=13, rotation=0, labelpad=14)
        ax.grid(True, linestyle="--", alpha=0.35)
        ax.legend(fontsize=9, loc="lower right")
        title = "With digitized points" if show_pts else "Fit only"
        ax.set_title(title, fontsize=10)

    fig.suptitle("Figure 10.38 – τ₂ for closed elliptic jet  "
                 r"($\tau_2 = \frac{a\,x^b}{1+c\,x^d}$,  R²=0.9997)",
                 fontsize=12)
    plt.tight_layout()
    plt.show()


if __name__ == "__main__":
    print("=" * 58)
    print("  τ₂ lookup  –  Figure 10.38  (closed jet)")
    print(f"  Formula: τ₂ = {_A}·x^{_B} / (1 + {_C}·x^{_D})")
    print(f"  R² = 0.9997   RMSE = 0.006   valid range: 0 – 2")
    print("=" * 58)
    print()
    try:
        raw = input("  Enter lt/B value (or press Enter to just show plot): ").strip()
        if raw == "":
            plot_figure()
        else:
            lt_B = float(raw)
            tau2 = get_tau2(lt_B)
            if not np.isnan(tau2):
                print(f"\n  τ₂ (closed jet) = {tau2:.6f}")
            plot_figure(query_x=lt_B)
    except ValueError:
        print("  Invalid input – please enter a number.")